test('flux d\'achat complet', async ({ page }) => {
  // 1. Connexion
  await page.goto('/login');
  await page.fill('input[name="email"]', 'test@example.com');
  await page.fill('input[name="password"]', 'test123');
  await page.click('button[type="submit"]');

  // 2. Recherche produit
  await page.fill('input[placeholder="Rechercher"]', 'Tee-shirt');
  await page.click('button[aria-label="Rechercher"]');
  await page.click('text=Tee-shirt Premium');

  // 3. Ajout au panier
  await page.click('button:has-text("Ajouter au panier")');
  await page.click('a:has-text("Voir le panier")');

  // 4. Validation panier
  await page.click('button:has-text("Valider la commande")');

  // 5. Adresse de livraison
  await page.fill('input[name="street"]', '123 Rue de Test');
  await page.fill('input[name="city"]', 'Yaoundé');
  await page.fill('input[name="postalCode"]', '00237');
  await page.click('button:has-text("Continuer vers paiement")');

  // 6. Paiement simulé
  await page.frameLocator('iframe[title="Secure payment input"]').locator('input[name="cardnumber"]').fill('4242424242424242');
  await page.click('button:has-text("Payer")');

  // 7. Vérification confirmation
  await expect(page.locator('text=Votre commande a été confirmée')).toBeVisible();
  await expect(page.locator('.order-number')).toBeVisible();
});
